let loading=!1;async function loadNextPage(){if(loading)return;const e=document.querySelector(".pagination a:last-child");if(!e)return;loading=!0;const n=await fetch(e.href),s=await n.text(),o=new DOMParser,t=o.parseFromString(s,"text/html"),i=t.querySelectorAll(".banner-card"),a=document.querySelector(".banner-list");i.forEach(e=>a.appendChild(e));const r=t.querySelector(".pagination");document.querySelector(".pagination").innerHTML=r.innerHTML,loading=!1}window.addEventListener("scroll",()=>{window.innerHeight+window.scrollY>=document.body.offsetHeight-100&&loadNextPage()});const bannerList=document.querySelector(".banner-list");bannerList&&bannerList.addEventListener("scroll",()=>{const e=bannerList.scrollLeft,t=bannerList.clientWidth,n=bannerList.scrollWidth;e+t>=n-50&&loadNextPage()})